import React from "react";
import { Row, Col } from "antd";
import { useDashboardPageHooks } from "./dashboard-page-hooks";
import ConsumedSparePartsTable from "./components/consumed-spare-parts-table/consumed-spare-parts-table";
import SmartMaintenanceGraph from "./components/smart-maintenance-graph/smart-maintenance-graph";
import DowntimeGraph from "./components/downtime-graph/downtime-graph";
// import RepairedEquipmentsGraph from "./components/repaired-equipment-graph/repaired-equipment-graph"
import SparePartsForecastGraph from "./components/spare-parts-forecast-graph/spare-parts-forecast-graph";
import RecommendationAccuracyGraph from "./components/recommendation-accuracy-graph/recommendation-accuracy-graph";

const DashboardPage = () => {
  useDashboardPageHooks();
  return (
    <div>
      <Row
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gridTemplateRows: "1fr",
        }}
      >
        <DowntimeGraph />
        <SmartMaintenanceGraph />
      </Row>
      <Row
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr 2fr",
          gridTemplateRows: "1fr",
        }}
      >
        <RecommendationAccuracyGraph />
        <SparePartsForecastGraph />
        <ConsumedSparePartsTable />

        {/* <RepairedEquipmentsGraph /> */}
      </Row>
    </div>
  );
};

const Box = () => {
  return <div style={{ width: "100%", height: "100%" }}> </div>;
};

export default DashboardPage;
